import {
  createComponent,
  createSystem,
  Types,
  Mesh,
  SphereGeometry,
  MeshBasicMaterial,
  Vector3,
  AdditiveBlending,
  RingGeometry,
  DoubleSide,
  Color,
  Object3D,
} from "@iwsdk/core";
import {
  TUNNEL_MIN_X,
  TUNNEL_MAX_X,
  TUNNEL_MIN_Y,
  TUNNEL_MAX_Y,
  TUNNEL_NEAR_Z,
  TUNNEL_FAR_Z,
  TUNNEL_WIDTH,
  TUNNEL_HEIGHT,
} from "./tunnel";

export const BALL_RADIUS = 0.06;
const BALL_SPEED = 3.0;
const PADDLE_HALF = 0.15; // half paddle size

export const BallTag = createComponent("BallTag", {
  vx: { type: Types.Float32, default: 0 },
  vy: { type: Types.Float32, default: 0 },
  vz: { type: Types.Float32, default: -BALL_SPEED },
  active: { type: Types.Boolean, default: false },
  pauseTimer: { type: Types.Float32, default: 1.5 },
});

// Bounce effect pool
interface BounceEffect {
  mesh: Mesh;
  life: number;
  maxLife: number;
}

export function createBallMesh(): Mesh {
  const geometry = new SphereGeometry(BALL_RADIUS, 16, 16);
  const material = new MeshBasicMaterial({
    color: new Color(0xffffff),
    transparent: true,
    opacity: 1.0,
    blending: AdditiveBlending,
  });
  const ball = new Mesh(geometry, material);

  // Add inner glow sphere
  const glowGeo = new SphereGeometry(BALL_RADIUS * 1.6, 16, 16);
  const glowMat = new MeshBasicMaterial({
    color: new Color(0x00ffff),
    transparent: true,
    opacity: 0.3,
    blending: AdditiveBlending,
  });
  const glow = new Mesh(glowGeo, glowMat);
  ball.add(glow);

  return ball;
}

export class BallSystem extends createSystem({
  balls: { required: [BallTag] },
}) {
  private bounceEffects: BounceEffect[] = [];
  private playerPaddleMesh: Object3D | null = null;
  private aiPaddleMesh: Object3D | null = null;
  private scoreCallback: ((scorer: "player" | "ai") => void) | null = null;
  private tempVec = new Vector3();

  setScoreCallback(cb: (scorer: "player" | "ai") => void) {
    this.scoreCallback = cb;
  }

  setPaddles(player: Object3D, ai: Object3D) {
    this.playerPaddleMesh = player;
    this.aiPaddleMesh = ai;
  }

  update(delta: number) {
    for (const entity of this.queries.balls.entities) {
      const obj = entity.object3D;
      if (!obj) continue;

      // Handle pause after goal
      const active = entity.getValue(BallTag, "active");
      if (!active) {
        let timer = entity.getValue(BallTag, "pauseTimer") - delta;
        entity.setValue(BallTag, "pauseTimer", timer);
        if (timer <= 0) {
          entity.setValue(BallTag, "active", true);
        }
        continue;
      }

      const vx = entity.getValue(BallTag, "vx");
      const vy = entity.getValue(BallTag, "vy");
      let vz = entity.getValue(BallTag, "vz");

      // Move ball
      obj.position.x += vx * delta;
      obj.position.y += vy * delta;
      obj.position.z += vz * delta;

      // --- Wall collisions ---
      // Left/right walls
      if (obj.position.x - BALL_RADIUS < TUNNEL_MIN_X) {
        obj.position.x = TUNNEL_MIN_X + BALL_RADIUS;
        entity.setValue(BallTag, "vx", Math.abs(vx));
        this.spawnBounceEffect(
          new Vector3(TUNNEL_MIN_X, obj.position.y, obj.position.z),
          new Vector3(1, 0, 0)
        );
      } else if (obj.position.x + BALL_RADIUS > TUNNEL_MAX_X) {
        obj.position.x = TUNNEL_MAX_X - BALL_RADIUS;
        entity.setValue(BallTag, "vx", -Math.abs(vx));
        this.spawnBounceEffect(
          new Vector3(TUNNEL_MAX_X, obj.position.y, obj.position.z),
          new Vector3(-1, 0, 0)
        );
      }

      // Top/bottom walls
      if (obj.position.y - BALL_RADIUS < TUNNEL_MIN_Y) {
        obj.position.y = TUNNEL_MIN_Y + BALL_RADIUS;
        entity.setValue(BallTag, "vy", Math.abs(vy));
        this.spawnBounceEffect(
          new Vector3(obj.position.x, TUNNEL_MIN_Y, obj.position.z),
          new Vector3(0, 1, 0)
        );
      } else if (obj.position.y + BALL_RADIUS > TUNNEL_MAX_Y) {
        obj.position.y = TUNNEL_MAX_Y - BALL_RADIUS;
        entity.setValue(BallTag, "vy", -Math.abs(vy));
        this.spawnBounceEffect(
          new Vector3(obj.position.x, TUNNEL_MAX_Y, obj.position.z),
          new Vector3(0, -1, 0)
        );
      }

      // --- Paddle collisions ---
      // Player paddle (at z ~ TUNNEL_NEAR_Z)
      if (this.playerPaddleMesh && vz > 0) {
        const pz = this.playerPaddleMesh.position.z;
        if (obj.position.z + BALL_RADIUS >= pz && obj.position.z - BALL_RADIUS <= pz + 0.05) {
          const px = this.playerPaddleMesh.position.x;
          const py = this.playerPaddleMesh.position.y;
          if (
            obj.position.x >= px - PADDLE_HALF &&
            obj.position.x <= px + PADDLE_HALF &&
            obj.position.y >= py - PADDLE_HALF &&
            obj.position.y <= py + PADDLE_HALF
          ) {
            // Bounce off player paddle
            obj.position.z = pz - BALL_RADIUS;
            // Add angle based on hit offset
            const offsetX = (obj.position.x - px) / PADDLE_HALF;
            const offsetY = (obj.position.y - py) / PADDLE_HALF;
            const speed = Math.sqrt(vx * vx + vy * vy + vz * vz);
            const newSpeed = Math.min(speed * 1.05, 8.0); // slight speed increase, cap at 8
            entity.setValue(BallTag, "vx", vx + offsetX * 1.5);
            entity.setValue(BallTag, "vy", vy + offsetY * 1.5);
            entity.setValue(BallTag, "vz", -newSpeed);
            // Re-normalize to maintain speed
            this.normalizeVelocity(entity, newSpeed);
            this.spawnBounceEffect(
              new Vector3(obj.position.x, obj.position.y, pz),
              new Vector3(0, 0, -1)
            );
          }
        }
      }

      // AI paddle (at z ~ TUNNEL_FAR_Z)
      if (this.aiPaddleMesh && entity.getValue(BallTag, "vz") < 0) {
        vz = entity.getValue(BallTag, "vz"); // re-read after potential player bounce
        const az = this.aiPaddleMesh.position.z;
        if (obj.position.z - BALL_RADIUS <= az && obj.position.z + BALL_RADIUS >= az - 0.05) {
          const ax = this.aiPaddleMesh.position.x;
          const ay = this.aiPaddleMesh.position.y;
          if (
            obj.position.x >= ax - PADDLE_HALF &&
            obj.position.x <= ax + PADDLE_HALF &&
            obj.position.y >= ay - PADDLE_HALF &&
            obj.position.y <= ay + PADDLE_HALF
          ) {
            obj.position.z = az + BALL_RADIUS;
            const offsetX = (obj.position.x - ax) / PADDLE_HALF;
            const offsetY = (obj.position.y - ay) / PADDLE_HALF;
            const speed = Math.sqrt(
              entity.getValue(BallTag, "vx") ** 2 +
              entity.getValue(BallTag, "vy") ** 2 +
              vz ** 2
            );
            const newSpeed = Math.min(speed * 1.05, 8.0);
            entity.setValue(BallTag, "vx", entity.getValue(BallTag, "vx") + offsetX * 1.5);
            entity.setValue(BallTag, "vy", entity.getValue(BallTag, "vy") + offsetY * 1.5);
            entity.setValue(BallTag, "vz", newSpeed);
            this.normalizeVelocity(entity, newSpeed);
            this.spawnBounceEffect(
              new Vector3(obj.position.x, obj.position.y, az),
              new Vector3(0, 0, 1)
            );
          }
        }
      }

      // --- Goal detection ---
      if (obj.position.z > TUNNEL_NEAR_Z + 0.3) {
        // Ball passed player's goal → AI scores
        if (this.scoreCallback) this.scoreCallback("ai");
        this.resetBall(entity);
      } else if (obj.position.z < TUNNEL_FAR_Z - 0.3) {
        // Ball passed AI's goal → Player scores
        if (this.scoreCallback) this.scoreCallback("player");
        this.resetBall(entity);
      }
    }

    // Update bounce effects
    this.updateBounceEffects(delta);
  }

  private normalizeVelocity(entity: any, targetSpeed: number) {
    const vx = entity.getValue(BallTag, "vx");
    const vy = entity.getValue(BallTag, "vy");
    const vz = entity.getValue(BallTag, "vz");
    const currentSpeed = Math.sqrt(vx * vx + vy * vy + vz * vz);
    if (currentSpeed > 0) {
      const scale = targetSpeed / currentSpeed;
      entity.setValue(BallTag, "vx", vx * scale);
      entity.setValue(BallTag, "vy", vy * scale);
      entity.setValue(BallTag, "vz", vz * scale);
    }
  }

  resetBall(entity: any) {
    const obj = entity.object3D;
    if (!obj) return;
    obj.position.set(0, TUNNEL_MIN_Y + TUNNEL_HEIGHT / 2, -TUNNEL_DEPTH / 2 + 0.5);
    // Random serve direction
    const angle = (Math.random() - 0.5) * 0.6;
    const angleY = (Math.random() - 0.5) * 0.4;
    const dir = Math.random() > 0.5 ? -1 : 1;
    entity.setValue(BallTag, "vx", Math.sin(angle) * BALL_SPEED * 0.3);
    entity.setValue(BallTag, "vy", Math.sin(angleY) * BALL_SPEED * 0.2);
    entity.setValue(BallTag, "vz", dir * BALL_SPEED);
    entity.setValue(BallTag, "active", false);
    entity.setValue(BallTag, "pauseTimer", 1.0);
    this.normalizeVelocity(entity, BALL_SPEED);
  }

  private spawnBounceEffect(position: Vector3, normal: Vector3) {
    const ringGeo = new RingGeometry(0.02, 0.15, 24);
    const ringMat = new MeshBasicMaterial({
      color: new Color(0x00ffff),
      transparent: true,
      opacity: 0.8,
      side: DoubleSide,
      blending: AdditiveBlending,
    });
    const ring = new Mesh(ringGeo, ringMat);
    ring.position.copy(position);
    // Orient ring to face along the normal
    ring.lookAt(position.clone().add(normal));
    this.world.scene.add(ring);
    this.bounceEffects.push({ mesh: ring, life: 0, maxLife: 0.3 });
  }

  private updateBounceEffects(delta: number) {
    for (let i = this.bounceEffects.length - 1; i >= 0; i--) {
      const effect = this.bounceEffects[i];
      effect.life += delta;
      const t = effect.life / effect.maxLife;
      if (t >= 1) {
        this.world.scene.remove(effect.mesh);
        effect.mesh.geometry.dispose();
        (effect.mesh.material as MeshBasicMaterial).dispose();
        this.bounceEffects.splice(i, 1);
      } else {
        const scale = 1 + t * 3;
        effect.mesh.scale.setScalar(scale);
        (effect.mesh.material as MeshBasicMaterial).opacity = 0.8 * (1 - t);
      }
    }
  }
}

const TUNNEL_DEPTH = Math.abs(TUNNEL_FAR_Z - TUNNEL_NEAR_Z);

