{"content":"#!/usr/bin/env python3
"""
Extract a build transcript from Hatch agent session JSONL files.

Reads the JSONL transcript from a subagent session (~/agents/agent-{id}/sessions/{id}.jsonl)
and writes a structured journal — similar to Claude Code's journal.py stop hook output.

Usage:
    python3 extract-agent-transcript.py --agent-id 1206c0d1-f4b0-4a4a-b24e-c790fb17e5f0 --output galaga-build.jsonl
    python3 extract-agent-transcript.py --agent-id 1206c0d1-f4b0-4a4a-b24e-c790fb17e5f0 --output galaga-build.md --format markdown
    python3 extract-agent-transcript.py --session-file /path/to/session.jsonl --output build.md --format markdown
"""

import argparse
import json
import os
import re
import sys
from datetime import datetime, timezone
from pathlib import Path

AGENTS_DIR = os.path.expanduser("~/agents")

# Truncation limits
RESULT_HEAD = 2000
RESULT_TAIL = 400
INPUT_HEAD = 1200
INPUT_TAIL = 200

# Tools whose input is file content (redact to keep readable)
FILE_OP_TOOLS = {"write", "edit"}
FILE_OP_REDACT_KEYS = {
    "write": ("content",),
    "edit": ("old_text", "new_text"),
}

def truncate(s, head=RESULT_HEAD, tail=RESULT_TAIL):
    if not s or len(s) <= head + tail + 64:
        return s, False
    return s[:head] + f"\n...[truncated {len(s) - head - tail} chars]...\n" + s[-tail:], True

def shrink_input(tool_name, args_str):
    """Redact large file-op payloads, truncate long values."""
    try:
        args = json.loads(args_str) if isinstance(args_str, str) else args_str
    except json.JSONDecodeError:
        return args_str

    if not isinstance(args, dict):
        return args

    redact_keys = set(FILE_OP_REDACT_KEYS.get(tool_name, ()))
    out = {}
    for k, v in args.items():
        if k in redact_keys and isinstance(v, str):
            out[k] = f"<{len(v)} chars>"
        elif isinstance(v, str) and len(v) > INPUT_HEAD:
            out[k] = v[:INPUT_HEAD] + f"...[truncated {len(v) - INPUT_HEAD} chars]"
        else:
            out[k] = v
    return out

def find_session_file(agent_id):
    """Locate the JSONL session file for a given agent."""
    agent_dir = Path(AGENTS_DIR) / f"agent-{agent_id}" / "sessions"
    if not agent_dir.exists():
        print(f"Agent directory not found: {agent_dir}", file=sys.stderr)
        sys.exit(1)

    jsonl_files = list(agent_dir.glob("*.jsonl"))
    if not jsonl_files:
        print(f"No session files found in {agent_dir}", file=sys.stderr)
        sys.exit(1)

    # Use the one matching the agent_id, or the largest one
    for f in jsonl_files:
        if agent_id in f.stem:
            return f
    return max(jsonl_files, key=lambda f: f.stat().st_size)

def parse_session(session_path):
    """Parse a Hatch agent session JSONL file into structured events."""
    journal = []
    stats = {
        "user_messages": 0,
        "assistant_messages": 0,
        "tool_calls": 0,
        "thinking_blocks": 0,
        "tools_used": {},
        "first_ts": None,
        "last_ts": None,
        "total_entries": 0,
        "files_written": set(),
        "files_read": set(),
    }

    pending_calls = {}  # call_id -> journal event

    with open(session_path, "r") as f:
        for line_num, raw in enumerate(f):
            raw = raw.strip()
            if not raw:
                continue
            try:
                entry = json.loads(raw)
            except json.JSONDecodeError:
                continue

            etype = entry.get("type")
            created_at = entry.get("created_at")

            if created_at:
                if not stats["first_ts"]:
                    stats["first_ts"] = created_at
                stats["last_ts"] = created_at

            if etype == "session_header":
                meta = {
                    "type": "session_meta",
                    "session_id": entry.get("session_id"),
                    "agent_id": entry.get("agent_id"),
                }
                journal.append(meta)
                continue

            if etype == "compaction_checkpoint":
                journal.append({
                    "type": "compaction",
                    "ts": created_at,
                    "note": "Context was compacted at this point",
                })
                continue

            if etype != "item":
                continue

            stats["total_entries"] += 1
            item = entry.get("item", {})
            item_type = item.get("type", "")
            source = entry.get("source", "")

            # --- User message ---
            if item_type in ("message", "message_parts") and item.get("role") == "user":
                stats["user_messages"] += 1
                text = item.get("text", "")
                if not text and item.get("parts"):
                    text = "\n".join(p.get("text", "") for p in item["parts"] if isinstance(p, dict))
                text_trunc, was_trunc = truncate(text, head=1000, tail=200)
                evt = {"ts": created_at, "type": "user_message", "content": text_trunc}
                if was_trunc:
                    evt["truncated"] = True
                journal.append(evt)

            # --- Developer message ---
            elif item_type in ("message", "message_parts") and item.get("role") == "developer":
                text = item.get("text", "")
                if not text and item.get("parts"):
                    text = "\n".join(p.get("text", "") for p in item["parts"] if isinstance(p, dict))
                text_trunc, was_trunc = truncate(text, head=500, tail=100)
                evt = {"ts": created_at, "type": "system_message", "content": text_trunc}
                if was_trunc:
                    evt["truncated"] = True
                journal.append(evt)

            # --- Assistant message ---
            elif item_type == "message" and item.get("role") == "assistant":
                stats["assistant_messages"] += 1
                text = item.get("text", "")
                text_trunc, was_trunc = truncate(text)
                evt = {"ts": created_at, "type": "assistant_text", "content": text_trunc}
                if was_trunc:
                    evt["truncated"] = True
                journal.append(evt)

            # --- Thinking block ---
            elif item_type == "thinking":
                stats["thinking_blocks"] += 1
                text = item.get("text", "")
                if text:
                    text_trunc, _ = truncate(text, head=500, tail=100)
                    journal.append({
                        "ts": created_at,
                        "type": "thinking",
                        "content": text_trunc,
                    })

            # --- Function call ---
            elif item_type == "function_call":
                stats["tool_calls"] += 1
                tool_name = item.get("name", "unknown")
                call_id = item.get("call_id")
                args_raw = item.get("arguments", "{}")

                stats["tools_used"][tool_name] = stats["tools_used"].get(tool_name, 0) + 1

                # Track file operations
                try:
                    args_parsed = json.loads(args_raw) if isinstance(args_raw, str) else args_raw
                    if tool_name == "write" and isinstance(args_parsed, dict):
                        stats["files_written"].add(args_parsed.get("path", ""))
                    elif tool_name == "read" and isinstance(args_parsed, dict):
                        stats["files_read"].add(args_parsed.get("path", ""))
                except:
                    args_parsed = args_raw

                shrunk = shrink_input(tool_name, args_raw)

                evt = {
                    "ts": created_at,
                    "type": "tool_call",
                    "tool": tool_name,
                    "call_id": call_id,
                    "input": shrunk,
                }
                journal.append(evt)
                if call_id:
                    pending_calls[call_id] = evt

            # --- Function call output ---
            elif item_type == "function_call_output":
                call_id = item.get("call_id")
                output = item.get("output", "")
                success = item.get("success", True)

                output_trunc, was_trunc = truncate(output)

                evt = {
                    "ts": created_at,
                    "type": "tool_result",
                    "call_id": call_id,
                    "success": success,
                }

                # Try to get tool name from pending call
                if call_id in pending_calls:
                    evt["tool"] = pending_calls[call_id].get("tool", "unknown")
                    del pending_calls[call_id]

                if output_trunc:
                    evt["result"] = output_trunc
                if was_trunc:
                    evt["truncated"] = True
                if not success:
                    evt["is_error"] = True

                journal.append(evt)

    # Finalize stats
    stats["files_written"] = sorted(stats["files_written"] - {""})
    stats["files_read"] = sorted(stats["files_read"] - {""})

    return journal, stats

def write_jsonl(journal, stats, output_path):
    """Write structured JSONL journal."""
    # Update session_meta if present
    for evt in journal:
        if evt.get("type") == "session_meta":
            evt.update({
                "started_at": stats["first_ts"],
                "ended_at": stats["last_ts"],
                "user_messages": stats["user_messages"],
                "assistant_messages": stats["assistant_messages"],
                "tool_calls": stats["tool_calls"],
                "thinking_blocks": stats["thinking_blocks"],
                "tools_used": stats["tools_used"],
                "files_written": stats["files_written"],
                "files_read": stats["files_read"],
            })
            break

    with open(output_path, "w") as f:
        for evt in journal:
            f.write(json.dumps(evt, ensure_ascii=False) + "\n")

    print(f"Written {len(journal)} events to {output_path}")
    _print_summary(stats)

def write_markdown(journal, stats, output_path):
    """Write human-readable markdown transcript."""
    with open(output_path, "w") as f:
        f.write("# Build Transcript\n\n")
        f.write(f"**Started:** {stats['first_ts']}  \n")
        f.write(f"**Ended:** {stats['last_ts']}  \n")
        f.write(f"**User messages:** {stats['user_messages']}  \n")
        f.write(f"**Assistant messages:** {stats['assistant_messages']}  \n")
        f.write(f"**Tool calls:** {stats['tool_calls']}  \n")
        f.write(f"**Thinking blocks:** {stats['thinking_blocks']}  \n\n")

        f.write("## Tools Used\n\n")
        for tool, count in sorted(stats["tools_used"].items(), key=lambda x: -x[1]):
            f.write(f"- `{tool}`: {count}x\n")

        if stats["files_written"]:
            f.write("\n## Files Written\n\n")
            for fp in stats["files_written"]:
                f.write(f"- `{fp}`\n")

        f.write("\n---\n\n## Timeline\n\n")

        for evt in journal:
            ts = evt.get("ts", "")
            etype = evt["type"]

            if etype == "session_meta":
                continue

            elif etype == "compaction":
                f.write(f"---\n\n*⚡ Context compacted at {ts}*\n\n---\n\n")

            elif etype == "user_message":
                f.write(f"### 👤 User ({ts})\n\n")
                f.write(evt.get("content", "") + "\n\n")

            elif etype == "system_message":
                f.write(f"### ⚙️ System ({ts})\n\n")
                content = evt.get("content", "")
                # Collapse long system messages
                if len(content) > 300:
                    f.write(f"<details><summary>System message ({len(content)} chars)</summary>\n\n")
                    f.write(content + "\n\n</details>\n\n")
                else:
                    f.write(content + "\n\n")

            elif etype == "assistant_text":
                f.write(f"### 🤖 Assistant ({ts})\n\n")
                f.write(evt.get("content", "") + "\n\n")

            elif etype == "thinking":
                content = evt.get("content", "")
                f.write(f"<details><summary>💭 Thinking ({ts})</summary>\n\n")
                f.write(content + "\n\n</details>\n\n")

            elif etype == "tool_call":
                tool = evt.get("tool", "unknown")
                f.write(f"#### 🔧 `{tool}`\n\n")
                inp = evt.get("input")
                if inp:
                    if isinstance(inp, str):
                        try:
                            inp = json.loads(inp)
                        except:
                            pass
                    if isinstance(inp, dict):
                        f.write(f"```json\n{json.dumps(inp, indent=2, ensure_ascii=False)}\n```\n\n")
                    else:
                        inp_str = str(inp)
                        f.write(f"```\n{inp_str}\n```\n\n")

            elif etype == "tool_result":
                tool = evt.get("tool", "")
                is_err = "❌ " if evt.get("is_error") else ""
                result = evt.get("result", "")
                if result:
                    result_trunc = result
                    if len(result) > 500:
                        f.write(f"<details><summary>{is_err}Result: `{tool}` ({len(result)} chars)</summary>\n\n")
                        f.write(f"```\n{result_trunc}\n```\n\n</details>\n\n")
                    else:
                        f.write(f"**{is_err}Result:** `{tool}`\n\n```\n{result_trunc}\n```\n\n")
                else:
                    f.write(f"**{is_err}Result:** `{tool}` *(empty)*\n\n")

        f.write("---\n*End of transcript*\n")

    print(f"Written markdown transcript to {output_path}")
    _print_summary(stats)

def _print_summary(stats):
    print(f"  Duration: {stats['first_ts']} → {stats['last_ts']}")
    print(f"  User messages: {stats['user_messages']}")
    print(f"  Assistant messages: {stats['assistant_messages']}")
    print(f"  Tool calls: {stats['tool_calls']}")
    print(f"  Thinking blocks: {stats['thinking_blocks']}")
    print(f"  Files written: {len(stats['files_written'])}")
    print(f"  Tools: {json.dumps(stats['tools_used'])}")

def main():
    parser = argparse.ArgumentParser(description="Extract Hatch agent build transcript")
    group = parser.add_mutually_exclusive_group(required=True)
    group.add_argument("--agent-id", help="Agent UUID to extract transcript for")
    group.add_argument("--session-file", help="Direct path to session JSONL file")
    parser.add_argument("--output", required=True, help="Output file path")
    parser.add_argument("--format", choices=["jsonl", "markdown"], default="jsonl")
    args = parser.parse_args()

    if args.session_file:
        session_path = Path(args.session_file)
    else:
        session_path = find_session_file(args.agent_id)

    print(f"Reading: {session_path} ({session_path.stat().st_size / 1024:.1f} KB)")

    journal, stats = parse_session(session_path)

    if args.format == "markdown":
        write_markdown(journal, stats, args.output)
    else:
        write_jsonl(journal, stats, args.output)

if __name__ == "__main__":
    main()
