  update(): void {
    this.screenSpaceDescendants.length = 0;

    this.queries.panels.entities.forEach((entity) => {
      const parent = entity.object3D;
      const document = PanelDocument.data.document[entity.index] as
        | UIKitDocument
        | undefined;

